import numpy as np

class ConvexHull4D:
    def __init__(self, points):
        self.points = self.validate_points(points)
        self.hull = None

    def validate_points(self, points):
        if not isinstance(points, list) or not points:
            raise ValueError("Input must be a non-empty list of points.")
        for point in points:
            if not isinstance(point, (list, tuple)) or len(point) != 4:
                raise ValueError("Each point must be a list or tuple of four dimensions.")
        return np.array(points)

    def compute_hull(self):
        if len(self.points) < 5:
            return self.handle_low_dimension_cases()
        self.hull = ConvexHull(self.points)
        return self.get_hull_vertices()

    def handle_low_dimension_cases(self):
        if len(self.points) == 1:
            return {"vertices": [self.points[0]], "hull": [self.points[0]]}
        elif len(self.points) == 2:
            return {"vertices": self.points.tolist(), "hull": self.points.tolist()}
        elif len(self.points) == 3:
            return {"vertices": self.points.tolist(), "hull": self.points.tolist()}
        elif len(self.points) == 4:
            return {"vertices": self.points.tolist(), "hull": self.points.tolist()}
        return {"vertices": [], "hull": []}

    def get_hull_vertices(self):
        return {"vertices": self.points[self.hull.vertices].tolist(), "hull": self.hull.simplices.tolist()}

def convex_hull_4d(points):
    ch = ConvexHull4D(points)
    return ch.compute_hull()

