class ConvexHull4D:
    def __init__(self, points):
        self.points = np.array(points)
        self.validate_points()

    def validate_points(self):
        if len(self.points) < 4:
            raise ValueError("At least 4 points are required to form a convex hull in 4D.")
        if not all(len(point) == 4 for point in self.points):
            raise ValueError("All points must be 4-dimensional.")

