import numpy as np
from scipy.spatial import ConvexHull

def validate_points(points):
    if not isinstance(points, np.ndarray):
        raise ValueError("Points must be a numpy array.")
    if points.ndim != 2 or points.shape[1] != 4:
        raise ValueError("All points must be in 4D space.")
    return True

def convex_hull_4d(points):
    validate_points(points)

    if len(points) < 5:
        raise ValueError("At least 5 points are required to form a convex hull in 4D.")

    hull = ConvexHull(points)
    return hull

def main():
    # Example usage
    points = np.array([
        [1, 2, 3, 4],
        [2, 3, 4, 5],
        [3, 4, 5, 6],
        [4, 5, 6, 7],
        [5, 6, 7, 8],
        [1, 1, 1, 1]
    ])

    try:
        hull = convex_hull_4d(points)
        print("Convex Hull vertices:", hull.vertices)
    except ValueError as e:
        print("Error:", e)

if __name__ == "__main__":
    main()

